import React, {useCallback, useEffect, useRef, useState} from "react";

import DynamicParameterCard from "../components/DataEntity/DynamicParameterCard";
import {useWebSocket, useWebSocketMessage} from "../components/webSocket/WebSocketProvider";


function Testpage() {
    const [params, setParams] = useState({});
    const [renderData, setRenderData] = useState({})

    const {sendMessage,isConnected} = useWebSocket();

    useEffect(() => {
        if (isConnected){
            sendMessage("page_init")
        }
    },[isConnected]);

    useWebSocketMessage(useCallback((data) => {
        setRenderData(data)
    }, []));
    return (
        <div>
            <DynamicParameterCard
                renderConfig={renderData}
                params={params}
                setParams={setParams}
            />
        </div>
    )
}

export default Testpage
